command:
// Génère une boutique : handout + stock tiré des compendiums OggDude, prix ajustés au lieu.
// Renseigne ici des images de fond si tu en déposes (onglet Fichiers) :
const IMAGES = { armurier: "", bazar: "", noir: "", droides: "", apothicaire: "" };
const TYPES = {
  armurier:   { label: "Armurier",            packs: ["world.oggdudeweapons", "world.oggdudearmor"], raretyMax: 6, mult: 1.0,
                noms: ["La Crosse Fumante", "Arsenal Denal", "Chez Krieg", "Le Canon Court"] },
  bazar:      { label: "Bazar & équipement",  packs: ["world.oggdudegear"], raretyMax: 5, mult: 1.0,
                noms: ["Le Comptoir de l'Étoile", "Bazar Ryloth", "Chez Maz", "L'Entrepôt du Secteur"] },
  noir:       { label: "Marché noir",         packs: ["world.oggdudeweapons", "world.oggdudegear"], raretyMin: 5, raretyMax: 10, mult: 2.0,
                noms: ["L'Arrière-salle", "Le Silencieux", "Cargo Fantôme", "Chez Vessk (sur invitation)"] },
  droides:    { label: "Droïdiste & tech",    packs: ["world.oggdudegear"], raretyMax: 7, mult: 1.1, motsCles: ["droid", "comlink", "datapad", "tool", "scanner", "slicer", "computer", "cybernetic"],
                noms: ["Circuits & Rouages", "Le Ferrailleur", "Atelier R-7", "Doc Circuit"] },
  apothicaire:{ label: "Apothicaire",         packs: ["world.oggdudegear"], raretyMax: 7, mult: 1.2, motsCles: ["stim", "medpac", "bacta", "medical", "antidote", "syringe", "emergency", "kolto"],
                noms: ["L'Alambic Vert", "Remèdes de Jashwik", "La Cuve", "Herbes & Hypos"] },
};
const LIEUX = [["-2","Noyau (Coruscant…)"],["-1","Planète du Noyau / axe commercial"],["0","Colonie / Bordure intérieure"],["+1","Bordure, planète isolée"],["+2","Bordure extérieure"],["+3","Espace sauvage"],["+4","Planète primitive"]];
const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: "Générer une boutique" },
  content: `
    <div class="form-group"><label>Type</label><select name="type">${Object.entries(TYPES).map(([k, v]) => `<option value="${k}">${v.label}</option>`).join("")}</select></div>
    <div class="form-group"><label>Lieu</label><select name="lieu">${LIEUX.map(([v, l]) => `<option value="${v}" ${v === "0" ? "selected" : ""}>${l} (rareté ${v})</option>`).join("")}</select></div>
    <div class="form-group"><label>Nombre d'articles</label><input type="number" name="n" value="8" min="3" max="20"/></div>
    <div class="form-group"><label><input type="checkbox" name="show"/> Montrer aux joueurs à la création</label></div>`,
  buttons: [{ action: "ok", label: "Générer", default: true,
    callback: (event, button) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(button.form).object }],
});
if (!fd) return;
const cfg = TYPES[fd.type], lieu = Number(fd.lieu);
let index = [];
for (const pid of cfg.packs) {
  const pack = game.packs.get(pid);
  if (!pack) continue;
  const idx = await pack.getIndex({ fields: ["system.rarity", "system.price", "type"] });
  for (const e of idx) index.push({ ...e, pack: pid });
}
if (!index.length) return ui.notifications.error("Aucun compendium disponible pour ce type.");
const rMin = cfg.raretyMin ?? 0, rMax = cfg.raretyMax ?? 10;
let stockPool = index.filter(e => {
  const r = Number(e.system?.rarity?.value ?? e.system?.rarity ?? 0);
  if (r < rMin || r > rMax) return false;
  if (cfg.motsCles && !cfg.motsCles.some(m => e.name.toLowerCase().includes(m))) return false;
  return Number(e.system?.price?.value ?? e.system?.price ?? 0) > 0;
});
if (stockPool.length < 3) stockPool = index.filter(e => Number(e.system?.price?.value ?? e.system?.price ?? 0) > 0);
const stock = [];
const poolCopy = [...stockPool];
for (let i = 0; i < Math.min(Number(fd.n), poolCopy.length); i++) {
  stock.push(poolCopy.splice(Math.floor(Math.random() * poolCopy.length), 1)[0]);
}
const nom = cfg.noms[Math.floor(Math.random() * cfg.noms.length)];
const rows = stock.map(e => {
  const r = Number(e.system?.rarity?.value ?? e.system?.rarity ?? 0);
  const base = Number(e.system?.price?.value ?? e.system?.price ?? 0);
  const prix = Math.round(base * cfg.mult * (1 + 0.15 * Math.max(0, lieu + Math.floor(r / 3))) / 5) * 5;
  return `<tr><td>@UUID[Compendium.${e.pack}.Item.${e._id}]{${e.name}}</td><td style="text-align:right">${prix.toLocaleString()} cr</td><td style="text-align:center">${r}</td></tr>`;
}).join("");
const dispo = lieu >= 0 ? `+${lieu}` : `${lieu}`;
const pages = [];
if (IMAGES[fd.type]) pages.push({ name: nom, type: "image", src: IMAGES[fd.type] });
pages.push({ name: "Étal", type: "text", title: { show: false }, text: { format: 1, content:
  `<h2>🛒 ${nom}</h2><p><em>${cfg.label} — modificateur de rareté local ${dispo}.</em></p>
   <table><thead><tr><th>Article</th><th>Prix</th><th>Rareté</th></tr></thead><tbody>${rows}</tbody></table>
   <p style="font-size:.9em">Négociation opposée pour marchander ; trouver autre chose :
   test de Négociation${fd.type === "noir" ? " remplacé par <strong>Système D</strong>" : ""} (difficulté selon rareté ${dispo}).</p>` } });
let folder = game.folders.find(f => f.name === "Boutiques" && f.type === "JournalEntry");
if (!folder) folder = await Folder.create({ name: "Boutiques", type: "JournalEntry" });
const journal = await JournalEntry.create({ name: `🛒 ${nom}`, folder: folder.id, pages,
  ownership: { default: fd.show ? CONST.DOCUMENT_OWNERSHIP_LEVELS.OBSERVER : CONST.DOCUMENT_OWNERSHIP_LEVELS.NONE } });
journal.sheet.render(true);
if (fd.show) journal.show();
ui.notifications.info(`Boutique « ${nom} » générée (${stock.length} articles).`);
